const https = require('https');
const http = require('http');
const { JSDOM } = require('jsdom');

async function fetchURLMetadata(url) {
  return new Promise((resolve, reject) => {
    const client = url.startsWith('https') ? https : http;
    client.get(url, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        const dom = new JSDOM(data);
        const document = dom.window.document;

        const title = document.querySelector('title') ? document.querySelector('title').textContent : '';
        const descriptionMeta = document.querySelector('meta[name="description"]');
        const description = descriptionMeta ? descriptionMeta.getAttribute('content') : '';

        const ogTags = {};
        const metaTags = document.querySelectorAll('meta[property^="og:"]');
        metaTags.forEach(tag => {
          if (tag.getAttribute('content')) {
            ogTags[tag.getAttribute('property')] = tag.getAttribute('content');
          }
        });

        resolve({ title, description, ogTags });
      });
    }).on('error', (err) => reject(err));
  });
}

// Example usage of fetchURLMetadata within a GCP Cloud Function
exports.fetchMetadata = async (req, res) => {
  const url = req.query.url;
  if (!url) {
    return res.status(400).send('URL parameter is required.');
  }

  try {
    const metadata = await fetchURLMetadata(url);
    res.status(200).json(metadata);
  } catch (err) {
    res.status(500).send('Error fetching URL metadata.');
  }
};